import re

# assume table is a list of rows, each row is a list [Film, Film, Date]
# example:
# table = [
#     ["Kodachrome film", "16 mm, daylight (ASA 10) & Type A (ASA 16)", "1935–1962"],
#     ...
# ]

def parse_year_range(s):
    m = re.search(r'(\d{4})\s*[-–]\s*(\d{4})', s)
    return int(m.group(1)), int(m.group(2)) if m else (None, None)

earliest = None
for row in table:
    description = row[1]
    date_str = row[2]
    if "16 mm" in description:
        start, _ = parse_year_range(date_str)
        if start is not None:
            if earliest is None or start < earliest:
                earliest = start

answer = earliest

# assume table is a list of dicts like:
# [{'Film': ..., 'Film_2': ..., 'Date': ...}, ...]
def parse_start(date_str):
    # date like "1935–1962" or "1974–2001"
    start = date_str.split('–')[0]
    return int(start)

