# assume `table` is a list of dicts, each dict representing a row with the column names as keys
def team_points(score_str):
    # score_str like "W 16–14" or "L 10–11"
    parts = score_str.split()
    if len(parts) < 2:
        return None
    points_part = parts[1]
    # split on en‑dash or hyphen
    for sep in ("–", "-"):
        if sep in points_part:
            return int(points_part.split(sep)[0])
    return None

